const fs = require('fs');
const f = $input.first().json;
const project = (f['Project'] || '').toString().trim();
const model = (f['Model'] || '').toString().trim();
const task = (f['Task'] || '').toString();
const isAdhoc = project === '' || project.charAt(0) === '(';
const defModel = model === '' || model.charAt(0) === '(';
const p = isAdhoc ? '' : project;
const m = defModel ? '' : model;
let body, ext;
if (p || m) {
  const spec = { prompt: task };
  if (p) spec.project = p;
  if (m) spec.model = m;
  body = JSON.stringify(spec); ext = 'json';
} else { body = task + '\n'; ext = 'txt'; }
const ts = new Date().toISOString().replace(/[-:]/g, '').replace(/\.\d+Z$/, 'Z');
const rand = Math.floor(Math.random() * 1e6).toString();
const fileName = ts + '-' + (p || 'adhoc') + '-n8n-' + rand + '.' + ext;
const finalPath = '/srv/jobs/inbox/' + fileName;
const partialPath = finalPath + '.partial';
// write-then-rename: the poller skips *.partial, then the rename atomically publishes
fs.writeFileSync(partialPath, body);
fs.renameSync(partialPath, finalPath);
let summary = 'queued: ' + finalPath;
summary += p ? ('  (project=' + p + ')') : '  (ad-hoc, no repo)';
if (m) summary += ('  (model=' + m + ')');
return [{ json: { summary, fileName, finalPath } }];
